    <https://euaiact.eu/resource/Principle/technical_robustness_and_safety>;
  euai:mentionedInChunk euai_c:7c0263683362fba0955bb649d91de984454db924;
  euai:relation euai_c:7c0263683362fba0955bb649d91de984454db924, <https://euaiact.eu/resource/Concept/human_agency_and_oversight>,
